function offlineCell(r) {
  if (r.cap === null || r.cap === undefined) return `&lt;td&gt;&lt;/td&gt;`
  if (r.cap_funding === null || r.cap_funding === undefined) return `&lt;td&gt;&lt;/td&gt;`
