  if (offline &lt;= 0) {
    return `&lt;td class="bq-num"&gt;${offline.toLocaleString()}&lt;/td&gt;`
  }
  return `&lt;td class="bq-num bq-danger"&gt;${offline.toLocaleString()}&lt;/td&gt;`
}

