xLine = ({
  type: "time",
  label: null,
  ticks: xLineSingle ? d3.utcMonth.every(1) : 8,
  tickFormat: d =&gt; {
    const m = d.getMonth(), y = d.getFullYear()
    if (xLineSingle)  return m === 0 ? `${MON[m]}-${y}` : MON[m]
    if (xLineDense)   return m === 0 ? String(y) : m === 6 ? `juill. ${y}` : ""
    return m === 0 ? `janv.-${y}` : m === 6 ? `juill.-${y}` : `${MON[m]}-${y}`
  }
})

