bqIndex = {
  const idx = new Map()
  ci.monthly.forEach(r =&gt; idx.set(r.year * 100 + r.month, r))
  return idx
}

passRef  = (bq, city) =&gt; bq != null && Math.abs(bq - city) &lt;= 0.10
passUnm  = (bq, city) =&gt; bq != null && Math.abs(bq - city) &lt;= 0.10
passHdl  = (bq, city) =&gt; bq != null && Math.abs(bq - city) &lt;= 1.0

mark = (pass, bqVal) =&gt;
  bqVal == null
    ? `&lt;span style="color:var(--bq-fg-disabled)"&gt;—&lt;/span&gt;`
    : pass
      ? `&lt;span style="color:var(--bq-success);font-weight:700"&gt;✓&lt;/span&gt;`
      : `&lt;span style="color:var(--bq-danger);font-weight:700"&gt;✗&lt;/span&gt;`

function valRow(c, i) {
  const bq  = bqIndex.get(c.year * 100 + c.month)
  const br  = bq ? bq.referred_mean  : null
  const bu  = bq ? bq.unmatched_mean : null
  const bh  = bq ? bq.handled_mean   : null
  const pr  = passRef(br, c.referred)
  const pu  = passUnm(bu, c.unmatched)
  const ph  = passHdl(bh, c.handled)

  const bg  = i % 2 === 0 ? "var(--bq-bg)" : "var(--bq-bg-alt)"
  const td  = `padding:5px 9px;text-align:center;border-bottom:1px solid var(--bq-border)`
  const tdb = td + ";border-left:2px solid var(--bq-chart-blue)"

  return html`&lt;tr style="background:${bg}"&gt;
    &lt;td style="${td}"&gt;${c.year}&lt;/td&gt;
    &lt;td style="${td}"&gt;${MONTH_ABB[c.month]}&lt;/td&gt;
    &lt;td style="${tdb}"&gt;${br != null ? br.toFixed(1) : "—"}&lt;/td&gt;
    &lt;td style="${td}"&gt;${c.referred.toFixed(1)}&lt;/td&gt;
    &lt;td style="${td}"&gt;${mark(pr, br)}&lt;/td&gt;
    &lt;td style="${tdb}"&gt;${bu != null ? bu.toFixed(1) : "—"}&lt;/td&gt;
    &lt;td style="${td}"&gt;${c.unmatched.toFixed(1)}&lt;/td&gt;
    &lt;td style="${td}"&gt;${mark(pu, bu)}&lt;/td&gt;
    &lt;td style="${tdb}"&gt;${bh != null ? Math.round(bh).toLocaleString("fr-CA") : "—"}&lt;/td&gt;
    &lt;td style="${td}"&gt;${c.handled.toLocaleString("fr-CA")}&lt;/td&gt;
    &lt;td style="${td}"&gt;${mark(ph, bh)}&lt;/td&gt;
  &lt;/tr&gt;`
}

valSummary = {
