daily_occ = FileAttachment("../data/daily_occupancy.json").json()
city_ref  = FileAttachment("../data/city_reference_2026-05-14.json").json()
















bq14 = daily_occ.filter(r =&gt; r.date === "2026-05-14")

function bq(key) { return bq14.find(r =&gt; r.key === key) }
function cr(key) { return city_ref.find(r =&gt; r.key === key) }

function n(v)   { return v !== null && v !== undefined ? (+v).toLocaleString("fr-CA") : "—" }
function pct(v) { return v !== null && v !== undefined ? (+v).toFixed(1) + " %" : "—" }

KNOWN_CAP_KEYS = new Set(["mix_emerg","men_emerg","wom_emerg","yth_emerg","emerg_total","singles_total"])

function mark(bqVal, cityVal, isCapOrRate, key) {
  if (cityVal === null || cityVal === undefined) return ""
  if (bqVal === null || bqVal === undefined) return ""
  const match = Math.abs(+bqVal - +cityVal) &lt; 0.11
  if (match) return `&lt;span style="color:var(--bq-success);font-weight:bold"&gt;✓&lt;/span&gt;`
  if (isCapOrRate && KNOWN_CAP_KEYS.has(key))
    return `&lt;span style="color:var(--bq-caution);font-weight:bold" title="Différence connue — voir notes"&gt;*&lt;/span&gt;`
  return ""
}

function compRow(key, bqRow, cityRow, opts = {}) {
  const { indent = 0, isTot = false, summaryOnly = false } = opts
  const pad  = indent * 16
  const bold = isTot ? "font-weight:600" : ""
  const bg   = isTot ? "var(--bq-bg-accent)" : "var(--bq-bg)"

  if (!bqRow || !cityRow) return ""

  if (summaryOnly || bqRow.col_type === "summary") {
    return `&lt;tr style="background:${bg}"&gt;
      &lt;td style="padding:5px 10px 5px ${pad}px;${bold}"&gt;${bqRow.label}&lt;/td&gt;
      &lt;td style="padding:5px 8px;text-align:right;${bold}"&gt;
        ${n(bqRow.ind)} ${mark(bqRow.ind, cityRow.city_ind, false, key)}&lt;/td&gt;
      &lt;td style="padding:5px 8px;text-align:right;color:var(--bq-fg-faint)"&gt;${n(cityRow.city_ind)}&lt;/td&gt;
      &lt;td colspan="6"&gt;&lt;/td&gt;
    &lt;/tr&gt;`
  }

  return `&lt;tr style="background:${bg}"&gt;
    &lt;td style="padding:5px 10px 5px ${pad}px;${bold}"&gt;${bqRow.label}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right;${bold}"&gt;
      ${n(bqRow.ind)} ${mark(bqRow.ind, cityRow.city_ind, false, key)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right;color:var(--bq-fg-faint)"&gt;${n(cityRow.city_ind)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right"&gt;
      ${n(bqRow.occ)} ${mark(bqRow.occ, cityRow.city_occ, false, key)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right;color:var(--bq-fg-faint)"&gt;${n(cityRow.city_occ)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right"&gt;
      ${n(bqRow.unocc)} ${mark(bqRow.unocc, cityRow.city_unocc, true, key)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right;color:var(--bq-fg-faint)"&gt;${n(cityRow.city_unocc)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right"&gt;
      ${n(bqRow.cap)}${bqRow.cap_funding != null && bqRow.cap_funding !== bqRow.cap ? ` &lt;span style="color:var(--bq-fg-faint);font-size:0.85em"&gt;(financé ${n(bqRow.cap_funding)})&lt;/span&gt;` : ""} ${mark(bqRow.cap, cityRow.city_cap, true, key)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right;color:var(--bq-fg-faint)"&gt;${n(cityRow.city_cap)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right"&gt;
      ${pct(bqRow.rate)} ${mark(bqRow.rate, cityRow.city_rate, true, key)}&lt;/td&gt;
    &lt;td style="padding:5px 8px;text-align:right;color:var(--bq-fg-faint)"&gt;${pct(cityRow.city_rate)}&lt;/td&gt;
  &lt;/tr&gt;`
}

